import { Pipe, PipeTransform } from "@angular/core";

/** Brackets a string or number, 
 * Handling input of null/undefined, empty and NaN.
*/
@Pipe({
   name: 'bracketed',
   pure: true,
})
export class BracketedPipe implements PipeTransform {
   transform(pos: number | string): string {
      if (!pos) {
         return '';
      }
      if (typeof pos ==='string') {
         return (pos === '') ? '' : `(${pos})`;
      } else {
      return isNaN(pos) ? '' : `(${pos.toString()})`;
      }
   }
}

import { Pipe, PipeTransform } from '@angular/core';

/** Pipe to format durations in seconds to hh:mm;ss string */
@Pipe({
  name: 'duration',
  pure: true,
})
export class DurationPipe implements PipeTransform {
  transform(totalSeconds: number | null | undefined): string | null {
    if (totalSeconds == null || totalSeconds <= 0) {
      return null;
    }

    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    const s = Math.floor(totalSeconds % 60);

    const pad = (n: number) => n.toString().padStart(2, '0');

    if (h > 0) {
      return `${pad(h)}:${pad(m)}:${pad(s)}`;
    }
    return `${pad(m)}:${pad(s)}`;
  }
}

import { Pipe, PipeTransform } from "@angular/core";

@Pipe({
   name: 'ellipsis',
   pure: true
})
export class EllipsisPipe implements PipeTransform {
   transform(val: string | null, args: number | undefined) {
      if (args === undefined) {
         return val;
      }

      if (val && val.length > args) {
         return val.substring(0, args) + '...';
      } else {
         return val;
      }
   }
}

import { Pipe, PipeTransform } from "@angular/core";
import { Race } from 'app/race-calender';

const formatter = new Intl.DateTimeFormat('en-GB', {
  day: '2-digit',
  month: 'short',
});

/** 
 * Title of a race object on a single line
*/
@Pipe({
  name: 'racetitle',
  pure: true,
})
export class RaceTitlePipe implements PipeTransform {
  transform(race: Race): string {
    const date = formatter.format(race.scheduledStart);
    const ret = `${race.seriesName} - R${race.index} - ${date}`;
    return (race.raceOfDay > 1) ? `${ret} / ${race.raceOfDay}` : ret;
  }
}

