import { Injectable, inject } from '@angular/core';
import { Race, RaceCalendarStore } from 'app/race-calender';
import { ResultCode } from 'app/scoring/model/result-code';
import { isFinishedComp } from 'app/scoring/model/result-code-scoring';
import { differenceInSeconds } from 'date-fns';
import { deleteField } from 'firebase/firestore';
import { RaceCompetitorStore, sortEntries } from './race-competitor-store';
import { RaceCompetitor } from '../model/race-competitor';

export class ExtendedRaceCompetitor extends RaceCompetitor {
  correctedTime?: number;
}

export interface ResultInput {
  finishTime: Date | null;
  laps: number;
  resultCode: ResultCode;
  position?: number | null;
}

/** Per-row editor state for pursuit / level-rating order entry UI */
export interface OrderEntryRowState {
  resultCode: ResultCode;
  /** Optional finish time for Level Rating (competitor info) */
  manualFinishTime?: Date | null;
  /** When set, overrides default sequential rank among finishers */
  rankOverride?: number | null;
}

export interface OrderEntryPersistInput {
  race: Race;
  /** All competitors for this race (from store) */
  competitors: RaceCompetitor[];
  /** Processed queue order (right pane), first = earliest processed */
  processedIds: string[];
  /** State keyed by competitor id for processed rows */
  rowState: Map<string, OrderEntryRowState>;
}

/**
 * Computes target manualPosition for finishers in processed order (ties share the same value).
 * Non-finishers (per isFinishedComp) get no rank (undefined).
 */
export function computeManualPositionsForOrderEntry(
  processedIds: string[],
  rowState: Map<string, OrderEntryRowState>
): Map<string, number | undefined> {
  const out = new Map<string, number | undefined>();
  let nextDefault = 1;
  for (const id of processedIds) {
    const row = rowState.get(id);
    if (!row) {
      out.set(id, undefined);
      continue;
    }
    const code = row.resultCode;
    if (!isFinishedComp(code)) {
      out.set(id, undefined);
      continue;
    }
    const ov = row.rankOverride;
    if (ov != null && !Number.isNaN(Number(ov))) {
      const p = Number(ov);
      out.set(id, p);
      nextDefault = Math.max(nextDefault, p + 1);
    } else {
      out.set(id, nextDefault);
      nextDefault++;
    }
  }
  return out;
}

export interface CalculatedStats {
  elapsedSeconds: number;
  avgLapTime: number;
}

export type TimeRecordingMode = 'tod' | 'elapsed';

@Injectable({
  providedIn: 'root'
})
export class ManualResultsService {
  private readonly competitorStore = inject(RaceCompetitorStore);
  private readonly raceStore = inject(RaceCalendarStore);

  /**
   * Calculates derived statistics for a result entry without persisting them.
   * This is useful for providing immediate feedback to the user in the UI.
   * @returns CalculatedStats or null if inputs are invalid.
   */
  calculateStats(finishTime: Date | null, laps: number, race: Race | undefined): CalculatedStats | null {
    if (!finishTime || !race?.actualStart || laps <= 0) {
      return null;
    }

    const elapsedSeconds = differenceInSeconds(finishTime, race.actualStart);

    if (elapsedSeconds <= 0) {
      return null;
    }

    const avgLapTime = elapsedSeconds / laps;

    return { elapsedSeconds, avgLapTime };
  }

  /** Set Start time 
   * Sets the race start time, updating any results 
   * where the start time has already been set. 
  */
  async setStartTime(raceId: string, startTime: Date, mode: TimeRecordingMode) {

    await this.raceStore.updateRace(raceId, {
      actualStart: startTime,
      timeInputMode: mode
    });

    // Update any competitors for the race that have already been saved 
    // TODO needs update to support multiple start times/race
    const comps = this.competitorStore.selectedCompetitors()
      .filter(comp => comp.raceId == raceId && comp.startTime);

    for (const comp of comps) {
      await this.competitorStore.updateResult(comp.id, { startTime: startTime });
    }

  }

  /**
   * Processes and saves a single competitor's result.
   * It calculates derived values and updates the competitor in the store.
   */
  async recordResult(competitor: RaceCompetitor, race: Race, input: ResultInput): Promise<void> {
    const { finishTime, laps, resultCode, position } = input;

    const update: Partial<RaceCompetitor> = {
      resultCode: resultCode,
    };

    if (race.actualStart) {
      update.startTime = race.actualStart;
    }

    if (finishTime) {
      update.manualFinishTime = finishTime;
    }

    if (laps) {
      update.manualLaps = laps;
    }

    if (position) {
      update.manualPosition = position;
    }

    // Set a dirty flag on the race to indicate that its results have changed
    // and may need re-scoring. We can build on this later.
    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    await this.competitorStore.updateResult(competitor.id, update);
  }

  /**
   * Computes target manualPosition for finishers in processed order.
   * Non-finishers (per isFinishedComp) get no rank (undefined).
   */
  computeManualPositionsForOrderEntry(
    processedIds: string[],
    rowState: Map<string, OrderEntryRowState>
  ): Map<string, number | undefined> {
    return computeManualPositionsForOrderEntry(processedIds, rowState);
  }

  /**
   * Persists order-entry state with diff-only writes (manualPosition, resultCode, manualFinishTime).
   */
  async persistOrderEntryState(input: OrderEntryPersistInput): Promise<void> {
    const { race, competitors, processedIds, rowState } = input;
    const processedSet = new Set(processedIds);
    const positions = computeManualPositionsForOrderEntry(processedIds, rowState);

    const updates: { id: string; patch: Record<string, unknown> }[] = [];

    for (const comp of competitors) {
      const inProcessed = processedSet.has(comp.id);
      const row = rowState.get(comp.id);
      const targetCode: ResultCode = inProcessed && row ? row.resultCode : 'NOT FINISHED';

      const targetManualFinish: Date | undefined | null =
        inProcessed && row ? row.manualFinishTime ?? undefined : undefined;

      const targetMp =
        inProcessed && row && isFinishedComp(targetCode) ? positions.get(comp.id) : undefined;

      const patch: Record<string, unknown> = {};

      if (comp.resultCode !== targetCode) {
        patch['resultCode'] = targetCode;
      }

      const prevTime = comp.manualFinishTime?.getTime();
      const nextTime = targetManualFinish instanceof Date ? targetManualFinish.getTime() : undefined;
      if (prevTime !== nextTime) {
        if (targetManualFinish === undefined || targetManualFinish === null) {
          if (prevTime !== undefined) {
            patch['manualFinishTime'] = deleteField();
          }
        } else {
          patch['manualFinishTime'] = targetManualFinish;
        }
      }

      const prevMp = comp.manualPosition;
      if (targetMp === undefined) {
        if (prevMp !== undefined && prevMp !== null) {
          patch['manualPosition'] = deleteField();
        }
      } else if (prevMp !== targetMp) {
        patch['manualPosition'] = targetMp;
      }

      if (Object.keys(patch).length > 0) {
        updates.push({ id: comp.id, patch });
      }
    }

    if (updates.length === 0) {
      return;
    }

    if (!race.dirty) {
      await this.raceStore.updateRace(race.id, { dirty: true });
    }

    for (const { id, patch } of updates) {
      await this.competitorStore.updateResult(id, patch as Partial<RaceCompetitor>);
    }
  }
}

/** Sorts partially completed results
 * Unfinished competitors are placed at the top sorted by class/sail number
 * followed by finished competitors sorted by key value. 
 */
export function manualRaceTableSort(
  a: ExtendedRaceCompetitor,
  b: ExtendedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  const aAwaitingResult = a.resultCode === 'NOT FINISHED';
  const bAwaitingResult = b.resultCode === 'NOT FINISHED';

  if (aAwaitingResult !== bAwaitingResult) {
    // If one has a result and the other doesnt, one with no result goes first
    return aAwaitingResult ? -1 : 1;
  } else if (aAwaitingResult && bAwaitingResult) {
    // Neither have a result sort by class / boat
    return sortEntries(a, b);
  } else {
    // Both have a result, so sort them accordingly
    return sortCompetitorsWithResult(a, b, finishedOrder, dir);
  }
}

export function sortCompetitorsWithResult(
  a: ExtendedRaceCompetitor,
  b: ExtendedRaceCompetitor,
  finishedOrder: keyof ExtendedRaceCompetitor,
  dir: 'asc' | 'desc' | ''
): number {

  if ((a.resultCode === 'OK') !== (b.resultCode === 'OK')) {
    /* If one is OK and the other not put the OK first  */
    return (a.resultCode === 'OK') ? -1 : 1;
  } else {
    // Both competitors OK - order by specified parameter
    const valueA = a[finishedOrder];
    const valueB = b[finishedOrder];
    let ret = 0;

    if (valueA === undefined || valueA === null || valueB === undefined || valueB === null) {
      if (valueA === valueB) {
        ret = 0;
      } else {
        // If one is missing a value, place the one with a value first
        ret = (valueA === undefined || valueA === null) ? 1 : -1;
      }
    } else if (valueA instanceof Date && valueB instanceof Date) {
      ret = valueA.getTime() - valueB.getTime();
    } else if (typeof valueA === 'number') {
      ret = (valueA as number) - (valueB as number);
    } else if (typeof valueA === 'string') {
      ret = valueA.localeCompare(valueB as string);
    } else {
      console.error('ManualResultsPage: Unexpected sort order: ' + finishedOrder);
      ret = 0;
    }
    return (dir === 'asc') ? ret : -ret;
  }
}

import { PublishedSeriesResult } from '../../published-results';
import { SeriesScoringScheme } from '../model/scoring-algotirhm';
import { PublishedRace } from '../../published-results/model/published-race';
import { getShortAlgorithm, includeInAveragePool, isDiscardable as isResultCodeDiscardable, ResultCodeAlgorithm, isStartAreaComp, isFinishedComp } from '../model/result-code-scoring';
import { SeriesEntry } from '../../results-input';

export interface ScoringConfig {
  seriesType: SeriesScoringScheme;
  discards: number;
  maxOodPerSeries?: number;
  oodAveragePool?: 'finished' | 'started';
}

/**
 * Intermediate data structure for series scoring calculations.
 */
export interface IntermediateSeriesResult extends PublishedSeriesResult {
}

/**
 * Aggregates pre-scored race results into a final, ranked series result.
 * @param races - An array of PublishedRace objects for the series.
 * @param seriesEntries - An array of SeriesEntry objects defining the competitors.
 * @param config - The scoring configuration for the series.
 * @returns An array of SeriesCompetitorResult, sorted by rank.
 */
export function scoreSeries(races: PublishedRace[], seriesEntries: SeriesEntry[], config: ScoringConfig): IntermediateSeriesResult[] {
  const competitorMap = aggregateCompetitorResults(races, seriesEntries);
  const resultsWithTotals = calculateTotalsAndDiscards(Array.from(competitorMap.values()), config);
  const rankedResults = rankCompetitors(resultsWithTotals);

  return rankedResults;
}

function aggregateCompetitorResults(races: PublishedRace[], seriesEntries: SeriesEntry[]): Map<string, IntermediateSeriesResult> {
  const competitorMap = new Map<string, IntermediateSeriesResult>();
  const dncPoints = seriesEntries.length + 1;

  seriesEntries.forEach(entry => {
    competitorMap.set(entry.id, {
      seriesEntryId: entry.id,
      helm: entry.helm,
      crew: entry.crew,
      sailNumber: entry.sailNumber,
      club: entry.club || '',
      handicap: entry.handicap,
      boatClass: entry.boatClass,
      raceScores: [],
      totalPoints: 0,
      netPoints: 0,
      rank: 0,
      scoresForTiebreak: [],
    });
  });

  races.forEach((race) => {
    const resultsByKey = new Map(race.results.map(r => [r.seriesEntryId, r]));
    competitorMap.forEach((seriesResult, seriesEntryId) => {
      const raceResult = resultsByKey.get(seriesEntryId);

      // If the race result has overrides for boat class, sail number, or handicap, 
      // we could potentially use them here. But for the series result summary, 
      // we typically display the default/primary boat details from the SeriesEntry.
      // We'll stick with the SeriesEntry defaults for the overall series display.

      if (raceResult) {
        seriesResult.raceScores.push({ 
          raceIndex: race.index, 
          points: raceResult.points, 
          resultCode: raceResult.resultCode, 
          isDiscard: false, 
        });
      } else {
        // Competitor did not compete in this race (DNC)
        seriesResult.raceScores.push({
          raceIndex: race.index,
          points: dncPoints,
          resultCode: 'DNC',
          isDiscard: false,
        });
      }
    });
  });

  return competitorMap;
}

function calculateTotalsAndDiscards(
  results: IntermediateSeriesResult[], 
  config: ScoringConfig): IntermediateSeriesResult[] {

  const dncPoints = results.length + 1;

  // Calculate total and net points after all races are processed
  for (const result of results) {

    // Apply average scores directly. This must be done before discards are calculated.
    applyIsafRedress(result, dncPoints);
    applyClubOod(result, dncPoints, config);

    // Identify discardable scores and sort them descending to find the worst ones.
    const scoresToDiscard = result.raceScores
      .filter(s => isResultCodeDiscardable(s.resultCode)) // Creates copy so original raceScore is not mutated
      .sort((a, b) => b.points - a.points)
      .slice(0, config.discards);

    // Set the isDiscard flag on the original raceScore objects
    scoresToDiscard.forEach(s => s.isDiscard = true);

    const scoresToCount = result.raceScores.filter(s => !s.isDiscard);

    result.netPoints = scoresToCount.reduce((acc, r) => acc + r.points, 0);
    result.totalPoints = result.raceScores.reduce((acc, r) => acc + r.points, 0);
  }
  return results;
}

/** Sets the points for ISAF Redress codes (RDGA, RDGB) */
function applyIsafRedress(result: IntermediateSeriesResult, dncPoints: number) {
  // ISAF Pool: All races except average codes (RDGA, RDGB, OOD)
  const isafPool = result.raceScores.filter(s => includeInAveragePool(s.resultCode));

  const isafAvgTotal = isafPool.reduce((acc, s) => acc + s.points, 0);
  const isafAvgAll = isafPool.length > 0 ? Math.round((isafAvgTotal / isafPool.length) * 10) / 10 : dncPoints;

  for (const score of result.raceScores) {
    const algorithm = getShortAlgorithm(score.resultCode);

    if (algorithm === ResultCodeAlgorithm.isafAvgAll) {
      score.points = isafAvgAll;
    } else if (algorithm === ResultCodeAlgorithm.isafAvgBefore) {
      const scoresBefore = isafPool.filter(s => s.raceIndex < score.raceIndex);
      if (scoresBefore.length > 0) {
        const totalBefore = scoresBefore.reduce((acc, s) => acc + s.points, 0);
        score.points = Math.round((totalBefore / scoresBefore.length) * 10) / 10;
      } else {
        score.points = dncPoints;
      }
    }
  }
}

/** Sets the points for Club OOD duties */
function applyClubOod(result: IntermediateSeriesResult, dncPoints: number, config: ScoringConfig) {
  const maxOod = config.maxOodPerSeries ?? 999;
  const oodPoolType = config.oodAveragePool ?? 'finished';

  // Base pool: All races except average codes
  const basePool = result.raceScores.filter(s => includeInAveragePool(s.resultCode));

  // OOD Pool: 'finished' (FINISHED_AND_SCORED) or 'started' (isStartAreaComp)
  const oodPool = basePool.filter(s => {
    if (oodPoolType === 'finished') return isFinishedComp(s.resultCode) && s.resultCode !== 'DNC';
    if (oodPoolType === 'started') return isStartAreaComp(s.resultCode);
    return false;
  });

  const oodAvgTotal = oodPool.reduce((acc, s) => acc + s.points, 0);
  const oodAvg = oodPool.length > 0 ? Math.round((oodAvgTotal / oodPool.length) * 10) / 10 : dncPoints;

  let oodCount = 0;

  // Process chronologically to correctly apply maxOodPerSeries cap
  const chronologicalScores = [...result.raceScores].sort((a, b) => a.raceIndex - b.raceIndex);

  for (const score of chronologicalScores) {
    const algorithm = getShortAlgorithm(score.resultCode);

    if (algorithm === ResultCodeAlgorithm.clubOodAverage) {
      if (oodCount < maxOod) {
        score.points = oodAvg;
        oodCount++;
      } else {
        score.points = dncPoints; // Cap reached
      }
    }
  }
}

function rankCompetitors(results: IntermediateSeriesResult[]): IntermediateSeriesResult[] {
  // For tie-breaking (A8.1), create a sorted list of scores for each competitor
  results.forEach(result => {
    result.scoresForTiebreak = result.raceScores.filter(r => !r.isDiscard).map(r => r.points).sort((a, b) => a - b);
  });

  results.sort((a, b) => {
    // Primary sort by net points (ascending)
    if (a.netPoints !== b.netPoints) {
      return a.netPoints - b.netPoints;
    }

    // Tie-break A8.1: most firsts, seconds, etc.
    for (let i = 0; i < Math.min(a.scoresForTiebreak.length, b.scoresForTiebreak.length); i++) {
      if (a.scoresForTiebreak[i] !== b.scoresForTiebreak[i]) {
        return a.scoresForTiebreak[i] - b.scoresForTiebreak[i];
      }
    }

    // Tie-break A8.2: score in the last race
    if (a.raceScores.length > 0 && b.raceScores.length > 0) {
      // Find the score from the most recent race (highest raceIndex)
      const lastRaceA = a.raceScores.reduce((prev, current) => (prev.raceIndex > current.raceIndex) ? prev : current);
      const lastRaceB = b.raceScores.find(s => s.raceIndex === lastRaceA.raceIndex)!;
      return lastRaceA.points - lastRaceB.points;
    }

    return 0;
  });

  // Assign ranks
  let currentRank = 1;
  for (let i = 0; i < results.length; i++) {
    if (i > 0 && isTied(results[i - 1], results[i])) {
      results[i].rank = results[i - 1].rank;
    } else {
      results[i].rank = currentRank;
    }
    currentRank++;
  }

  return results;
}

function isTied(a: IntermediateSeriesResult, b: IntermediateSeriesResult): boolean {
  if (a.netPoints !== b.netPoints) {
    return false;
  }

  if (a.scoresForTiebreak.length !== b.scoresForTiebreak.length) {
    return false;
  }

  for (let i = 0; i < a.scoresForTiebreak.length; i++) {
    if (a.scoresForTiebreak[i] !== b.scoresForTiebreak[i]) {
      return false;
    }
  }

  return true;
}

