import { inject, Injectable } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { firstValueFrom } from 'rxjs';
import { BoatsDupDialogData, BoatsDuplicatesDialog } from './boats-duplicates-dialog';
import { Boat, BoatsStore } from 'app/boats';

@Injectable({
  providedIn: 'root'
})
export class DuplicateBoatCheck {
  private snackbar = inject(MatSnackBar);
  private dialog = inject(MatDialog);
  private bs = inject(BoatsStore);

  async duplicateCheck(boat: Partial<Boat>): Promise<boolean> {

    const check = checkForDuplicateBoats(boat, this.bs.boats());

    if (check.isDuplicate) {
      this.snackbar.open("Duplicate Boat exists in boat repository", "Dismiss", { duration: 4000 });
      return false;
    } else if (check.matches.length > 0) {
      return await this.showDialog(boat as Boat, check.matches);
    }
    return true;
  }

  async showDialog(boat: Boat, dups: Boat[]): Promise<boolean> {

    const dialogRef = this.dialog.open<BoatsDuplicatesDialog, BoatsDupDialogData>(BoatsDuplicatesDialog, {
      data: { boat: boat, possibleDuplicates: dups },
    });
    return firstValueFrom(dialogRef.afterClosed());
  }
}

/** Checks for duplicate boats, returning a list of boats that
 * match exactly and ones that are similar to 
*/
function checkForDuplicateBoats(newBoat: Partial<Boat>, allBoats: Boat[]): { isDuplicate: boolean, matches: Boat[]; } {
  const possibles = allBoats.filter(
    boat => boat.boatClass === newBoat.boatClass &&
      boat.sailNumber === newBoat.sailNumber);

  const isDuplicate = possibles.find(boat => boat.helm.toLowerCase() === newBoat.helm?.toLowerCase()) !== undefined;

  return { isDuplicate, matches: possibles };
}

import { Injectable, inject } from '@angular/core';
import { RaceCalendarStore } from 'app/race-calender';
import { SeriesEntryStore } from 'app/results-input/services/series-entry-store';
import { ScoreSmarterError } from 'app/shared/utils/scoresmarter-error';
import { ClubStore } from '../../club-tenant';
import { Race } from '../../race-calender/model/race';
import { RaceCompetitor } from '../../results-input/model/race-competitor';
import { RaceCompetitorStore } from '../../results-input/services/race-competitor-store';

export interface EntryDetails {
  races: Race[];
  helm: string;
  crew?: string;
  boatClass: string;
  sailNumber: number;
  handicap?: number;
}

@Injectable({
  providedIn: 'root'
})
export class EntryService {
  private clubStore = inject(ClubStore);
  private raceResultsStore = inject(RaceCompetitorStore);
  private seriesEntryStore = inject(SeriesEntryStore);
  private raceCalanderStore = inject(RaceCalendarStore);

  /** Enter a race 
   * throws a ScoreSmarterError exception if the entry is a duplicate. 
   * @
   */
  async enterRaces(details: EntryDetails): Promise<void> {

    if (this.isDuplicateEntry(details)) {
      throw new ScoreSmarterError("Duplicate entry");
    }

    // Populate handicap based on the classes handicap if not provided
    let handicap = details.handicap;
    if (!handicap) {
      const boatClass = this.clubStore.club().classes.find(c => c.name === details.boatClass);
      handicap = boatClass?.handicap ?? 1;
    }

    for (const race of details.races) {

      const seriesEntryId = 
        await this.createSeriesEntryIfRequired(race, details, handicap);

      const competitor: Partial<RaceCompetitor> = {
        raceId: race.id,
        seriesId: race.seriesId,
        seriesEntryId: seriesEntryId,
        helm: details.helm,
        crew: details.crew,
        boatClass: details.boatClass,
        sailNumber: details.sailNumber,
        handicap: handicap,
        resultCode: 'NOT FINISHED'
      };

     await this.raceResultsStore.addResult(competitor);

    }
  }

  /** 
   * Check if a boat (class+sailnumber) is already entered
   * in any of the races being entered.
   * Returns true if a duplicate is found.
   */
  isDuplicateEntry(details: EntryDetails): boolean {
    for (const race of details.races) {
      const dup = this.raceResultsStore.selectedCompetitors().find(comp =>
        comp.boatClass === details.boatClass &&
        comp.raceId === race.id &&
        comp.sailNumber == details.sailNumber);
      if (dup) {
        return true;
      }
    }

    return false;
  }

  /** Finds a series entry if it exists or not 
   */
  async createSeriesEntryIfRequired(race: Race, details: EntryDetails, handicap: number): Promise<string> {
    const seriesEntries = this.seriesEntryStore.selectedEntries()
      .filter(seriesEntry => seriesEntry.seriesId === race.seriesId);

    const series = this.raceCalanderStore.allSeries().find(s => s.id = race.seriesId);
    if (!series) {
      const msg = 'EntryService:  Series not found for race: ' + race.toString();
      console.error(msg);
      throw new ScoreSmarterError(msg);
    }

    let entry;
    switch (series.entryAlgorithm) {
      case 'classSailNumberHelm':
        entry = seriesEntries.find(e =>
          e.boatClass === details.boatClass &&
          e.sailNumber === details.sailNumber &&
          e.helm == details.helm);
        break;
      case 'classSailNumber':
        entry = seriesEntries.find(e =>
          e.boatClass === details.boatClass &&
          e.sailNumber === details.sailNumber);
        break;
      case 'helm':
        entry = seriesEntries.find(e => e.helm === details.helm);
        break;
      default:
        throw new ScoreSmarterError('invalid entry algorithm');
    }
    if (entry) {
      return entry.id;
    }

    console.log(`EntryService: Adding series entry ${race.seriesName} index: ${race.index}`);

    const entryId = await this.seriesEntryStore.addEntry({
      seriesId: race.seriesId,
      helm: details.helm,
      crew: details.crew,
      boatClass: details.boatClass,
      sailNumber: details.sailNumber,
      handicap: handicap,
      tags: [],
    });

    return entryId;

  }
}

import { inject, Injectable } from '@angular/core';
import { collection, CollectionReference, doc, DocumentReference, Firestore } from '@angular/fire/firestore';
import { classInstanceConverter, dataObjectConverter } from '../../shared/firebase/firestore-helper';
import { ClubTenant } from './club-tenant';

@Injectable({
  providedIn: 'root'
})
export class FirestoreTenantService {
  private firestore = inject(Firestore);
  private clubContext = inject(ClubTenant);

  private get clubId(): string {
    const clubId = this.clubContext.clubId;
    if (!clubId) {
      // This will provide a clearer error if the service is used before the club context is ready.
      throw new Error('FirestoreTenantService: Club ID not available in context.');
    }
    return clubId;
  }

  /** Creates a typed DocumentReference for a document within the current club's tenant space. 
   * @param path Path segments of the document
  */
  docRef<T>(...path: string[]): DocumentReference<T> {
    return doc(this.firestore, 'clubs', this.clubId, ...path).withConverter(dataObjectConverter<T>());
  }

  /** Creates a typed CollectionReference for a sub-collection within the current club's tenant space. 
   * @param path Path of Firestore collection
  */
  collectionRef<T>(...path: string[]): CollectionReference<T> {
    return collection(this.firestore, 'clubs', this.clubId, ...path)
       .withConverter(dataObjectConverter<T>());
  }

  /** Creates a typed CollectionReference for a sub-collection of class instances within the current club's tenant space.
   * @param constructor Constructor for the class
   * @param path Path of Firestore collection
   */
  collectionOf<T>(constructor: new (data: Partial<T>) => T, ...path: string[]): CollectionReference<T> {
    return collection(this.firestore, 'clubs', this.clubId, ...path)
      .withConverter(classInstanceConverter<T>(constructor));
  }
}

import { Injectable, Injector, ProviderToken } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class LazyInject {
   constructor(private injector: Injector) { }

   async get<T>(providerLoader: () => Promise<ProviderToken<T>>): Promise<T> {
      return this.injector.get(await providerLoader());
   }

   /**
    * Simplifies getting a provider from a dynamically imported module.
    * This is more type-safe than the basic `get` as it can infer the return
    * type and validate the provider name at compile time.
    * @param moduleLoader A function that returns a promise to a module, e.g., `() => import('@angular/material/dialog')`.
    * @param providerName The string name of the exported provider class/token from the module, e.g., `'MatDialog'`.
    */
   async getProvider<M, K extends keyof M>(
      moduleLoader: () => Promise<M>,
      providerName: K
   ): Promise<M[K] extends ProviderToken<infer I> ? I : never> {
      const module = await moduleLoader();
      const providerToken = module[providerName] as ProviderToken<any>;
      return this.injector.get(providerToken);
   }
}

