  registerOnChange(fn: any): void {
    this.onChange = fn;
  }

  registerOnTouched(fn: any): void {
    this.onTouched = fn;
  }

  onSelectionChange(value: ResultCode) {
    this.value.set(value);
    this.onChange(value);
    this.onTouched();
  }
}

