computed(() => {
    const filter = normaliseString(this.subseriesFilter());

    return this.seasons().map((season) => ({
      ...season,
      series: season.series
        .filter(s => !s.baseSeriesId || s.id === s.baseSeriesId) // Show primary series in the list
        .filter((primarySeries) => {
